insert into konzepte (id, modul_nr, themenblock_id, titel, ist_rechnerisch, voraussetzungen, freischalt_level, erklaerungen, stufen, type, pedagogy, glossary_terms, teacher_support, parent_support) values
  ('konzept_geld', 1, 'tb_geld_wert_entscheidungen', '{"de":"Was ist Geld?"}'::jsonb, false, '{}'::text[], 1, '{"learners_10_14":"Was ist Geld?: Geld funktioniert, weil Menschen es akzeptieren und ihm vertrauen. Beispiel: Du kaufst ein Getränk und bezahlst mit Geld, statt direkt etwas zu tauschen. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Geld ist wertvoll, weil Papier oder Metall selbst so wertvoll sind.“.","young_adults":"Was ist Geld?: Geld funktioniert, weil Menschen es akzeptieren und ihm vertrauen. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Du kaufst ein Getränk und bezahlst mit Geld, statt direkt etwas zu tauschen.","parents_teachers":"Lernziel: Geld als Zahlungsmittel, Recheneinheit und Wertaufbewahrung verstehen. Didaktischer Fokus: Geld funktioniert, weil Menschen es akzeptieren und ihm vertrauen. Typische Fehlvorstellung: „Geld ist wertvoll, weil Papier oder Metall selbst so wertvoll sind.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'understanding', '{"learningGoal":"Geld als Zahlungsmittel, Recheneinheit und Wertaufbewahrung verstehen.","coreIdea":"Geld funktioniert, weil Menschen es akzeptieren und ihm vertrauen.","everydayScenario":"Du kaufst ein Getränk und bezahlst mit Geld, statt direkt etwas zu tauschen.","misconception":"Geld ist wertvoll, weil Papier oder Metall selbst so wertvoll sind.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Was ist Geld?'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Was ist Geld?'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Geld', 'Bargeld', 'Kontoguthaben', 'Zahlungsmittel', 'Preis', 'Wert', 'Vertrauen']::text[], '{"competenceGoal":"Geld als Zahlungsmittel, Recheneinheit und Wertaufbewahrung verstehen.","typicalMisconception":"Geld ist wertvoll, weil Papier oder Metall selbst so wertvoll sind.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Geld ist wertvoll, weil Papier oder Metall selbst so wertvoll sind.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Was ist Geld?“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Was ist Geld?“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Was ist Geld?“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
  ('konzept_tauschen', 2, 'tb_geld_wert_entscheidungen', '{"de":"Warum tauschen Menschen?"}'::jsonb, false, ARRAY['konzept_geld']::text[], 1, '{"learners_10_14":"Warum tauschen Menschen?: Menschen tauschen, weil nicht jeder alles selbst herstellen kann. Beispiel: Eine Person hat Äpfel, eine andere Brot; Geld macht den Tausch flexibler. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Tauschen ist altmodisch und hat mit Geld nichts mehr zu tun.“.","young_adults":"Warum tauschen Menschen?: Menschen tauschen, weil nicht jeder alles selbst herstellen kann. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Eine Person hat Äpfel, eine andere Brot; Geld macht den Tausch flexibler.","parents_teachers":"Lernziel: Tausch als Grundlage wirtschaftlicher Zusammenarbeit verstehen. Didaktischer Fokus: Menschen tauschen, weil nicht jeder alles selbst herstellen kann. Typische Fehlvorstellung: „Tauschen ist altmodisch und hat mit Geld nichts mehr zu tun.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'understanding', '{"learningGoal":"Tausch als Grundlage wirtschaftlicher Zusammenarbeit verstehen.","coreIdea":"Menschen tauschen, weil nicht jeder alles selbst herstellen kann.","everydayScenario":"Eine Person hat Äpfel, eine andere Brot; Geld macht den Tausch flexibler.","misconception":"Tauschen ist altmodisch und hat mit Geld nichts mehr zu tun.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Warum tauschen Menschen?'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Warum tauschen Menschen?'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Tausch', 'Handel', 'Angebot', 'Nachfrage', 'Arbeitsteilung', 'Geld']::text[], '{"competenceGoal":"Tausch als Grundlage wirtschaftlicher Zusammenarbeit verstehen.","typicalMisconception":"Tauschen ist altmodisch und hat mit Geld nichts mehr zu tun.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Tauschen ist altmodisch und hat mit Geld nichts mehr zu tun.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Warum tauschen Menschen?“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Warum tauschen Menschen?“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Warum tauschen Menschen?“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
  ('konzept_bezahlen_vergleichen', 3, 'tb_geld_wert_entscheidungen', '{"de":"Kaufen, bezahlen, vergleichen"}'::jsonb, true, ARRAY['konzept_tauschen']::text[], 1, '{"learners_10_14":"Kaufen, bezahlen, vergleichen: Nicht nur der niedrigste Preis zählt, sondern auch Menge, Qualität und Bedarf. Beispiel: Ein Viererpack kostet 8 Euro, ein einzelnes Getränk 3 Euro; pro Stück ist der Vergleich entscheidend. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Das billigste Angebot ist immer die beste Entscheidung.“.","young_adults":"Kaufen, bezahlen, vergleichen: Nicht nur der niedrigste Preis zählt, sondern auch Menge, Qualität und Bedarf. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Ein Viererpack kostet 8 Euro, ein einzelnes Getränk 3 Euro; pro Stück ist der Vergleich entscheidend.","parents_teachers":"Lernziel: Preise, Menge, Qualität und Nutzen bei Kaufentscheidungen vergleichen. Didaktischer Fokus: Nicht nur der niedrigste Preis zählt, sondern auch Menge, Qualität und Bedarf. Typische Fehlvorstellung: „Das billigste Angebot ist immer die beste Entscheidung.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'calculation', '{"learningGoal":"Preise, Menge, Qualität und Nutzen bei Kaufentscheidungen vergleichen.","coreIdea":"Nicht nur der niedrigste Preis zählt, sondern auch Menge, Qualität und Bedarf.","everydayScenario":"Ein Viererpack kostet 8 Euro, ein einzelnes Getränk 3 Euro; pro Stück ist der Vergleich entscheidend.","misconception":"Das billigste Angebot ist immer die beste Entscheidung.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Kaufen, bezahlen, vergleichen'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Kaufen, bezahlen, vergleichen'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Kaufen', 'Bezahlen', 'Preis', 'Grundpreis', 'Qualität', 'Nutzen', 'Gesamtkosten']::text[], '{"competenceGoal":"Preise, Menge, Qualität und Nutzen bei Kaufentscheidungen vergleichen.","typicalMisconception":"Das billigste Angebot ist immer die beste Entscheidung.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Das billigste Angebot ist immer die beste Entscheidung.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Kaufen, bezahlen, vergleichen“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Kaufen, bezahlen, vergleichen“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Kaufen, bezahlen, vergleichen“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
  ('konzept_beduerfnisse_wuensche', 4, 'tb_geld_wert_entscheidungen', '{"de":"Bedürfnisse vs. Wünsche"}'::jsonb, false, ARRAY['konzept_bezahlen_vergleichen']::text[], 1, '{"learners_10_14":"Bedürfnisse vs. Wünsche: Bedürfnisse sind wichtig oder notwendig; Wünsche sind erlaubt, müssen aber priorisiert werden. Beispiel: Du brauchst neue Sportschuhe, möchtest aber auch ein neues Spiel kaufen. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Wünsche sind schlecht und man darf nur notwendige Dinge kaufen.“.","young_adults":"Bedürfnisse vs. Wünsche: Bedürfnisse sind wichtig oder notwendig; Wünsche sind erlaubt, müssen aber priorisiert werden. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Du brauchst neue Sportschuhe, möchtest aber auch ein neues Spiel kaufen.","parents_teachers":"Lernziel: Zwischen Bedürfnissen, Wünschen und Prioritäten unterscheiden. Didaktischer Fokus: Bedürfnisse sind wichtig oder notwendig; Wünsche sind erlaubt, müssen aber priorisiert werden. Typische Fehlvorstellung: „Wünsche sind schlecht und man darf nur notwendige Dinge kaufen.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'decision', '{"learningGoal":"Zwischen Bedürfnissen, Wünschen und Prioritäten unterscheiden.","coreIdea":"Bedürfnisse sind wichtig oder notwendig; Wünsche sind erlaubt, müssen aber priorisiert werden.","everydayScenario":"Du brauchst neue Sportschuhe, möchtest aber auch ein neues Spiel kaufen.","misconception":"Wünsche sind schlecht und man darf nur notwendige Dinge kaufen.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Bedürfnisse vs. Wünsche'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Bedürfnisse vs. Wünsche'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Bedürfnis', 'Wunsch', 'Priorität', 'Entscheidung', 'Konsum', 'Sparziel']::text[], '{"competenceGoal":"Zwischen Bedürfnissen, Wünschen und Prioritäten unterscheiden.","typicalMisconception":"Wünsche sind schlecht und man darf nur notwendige Dinge kaufen.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Wünsche sind schlecht und man darf nur notwendige Dinge kaufen.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Bedürfnisse vs. Wünsche“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Bedürfnisse vs. Wünsche“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Bedürfnisse vs. Wünsche“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
  ('konzept_sparen', 5, 'tb_geld_wert_entscheidungen', '{"de":"Sparen vs. Ausgeben"}'::jsonb, true, ARRAY['konzept_beduerfnisse_wuensche']::text[], 1, '{"learners_10_14":"Sparen vs. Ausgeben: Ausgeben bedeutet Nutzen jetzt; Sparen bedeutet Möglichkeit später. Beispiel: Du bekommst 20 Euro und legst 5 Euro für ein größeres Ziel zurück. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Sparen heißt, sich nie etwas zu gönnen.“.","young_adults":"Sparen vs. Ausgeben: Ausgeben bedeutet Nutzen jetzt; Sparen bedeutet Möglichkeit später. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Du bekommst 20 Euro und legst 5 Euro für ein größeres Ziel zurück.","parents_teachers":"Lernziel: Sparen als bewusste Entscheidung für spätere Möglichkeiten verstehen. Didaktischer Fokus: Ausgeben bedeutet Nutzen jetzt; Sparen bedeutet Möglichkeit später. Typische Fehlvorstellung: „Sparen heißt, sich nie etwas zu gönnen.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'calculation', '{"learningGoal":"Sparen als bewusste Entscheidung für spätere Möglichkeiten verstehen.","coreIdea":"Ausgeben bedeutet Nutzen jetzt; Sparen bedeutet Möglichkeit später.","everydayScenario":"Du bekommst 20 Euro und legst 5 Euro für ein größeres Ziel zurück.","misconception":"Sparen heißt, sich nie etwas zu gönnen.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Sparen vs. Ausgeben'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Sparen vs. Ausgeben'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Sparen', 'Ausgeben', 'Sparziel', 'Sparrate', 'Planung', 'Puffer']::text[], '{"competenceGoal":"Sparen als bewusste Entscheidung für spätere Möglichkeiten verstehen.","typicalMisconception":"Sparen heißt, sich nie etwas zu gönnen.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Sparen heißt, sich nie etwas zu gönnen.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Sparen vs. Ausgeben“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Sparen vs. Ausgeben“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Sparen vs. Ausgeben“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
  ('konzept_budget', 6, 'tb_geld_wert_entscheidungen', '{"de":"Budget: Einnahmen und Ausgaben"}'::jsonb, true, ARRAY['konzept_sparen']::text[], 2, '{"learners_10_14":"Budget: Einnahmen und Ausgaben: Ein Budget zeigt, ob dein Geld reicht und was übrig bleibt. Beispiel: Du bekommst Taschengeld und planst Snacks, Freizeit, Sparen und Restbetrag. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Solange noch Geld auf dem Konto ist, ist alles in Ordnung.“.","young_adults":"Budget: Einnahmen und Ausgaben: Ein Budget zeigt, ob dein Geld reicht und was übrig bleibt. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Du bekommst Taschengeld und planst Snacks, Freizeit, Sparen und Restbetrag.","parents_teachers":"Lernziel: Einnahmen, Ausgaben und verfügbares Geld planen. Didaktischer Fokus: Ein Budget zeigt, ob dein Geld reicht und was übrig bleibt. Typische Fehlvorstellung: „Solange noch Geld auf dem Konto ist, ist alles in Ordnung.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'calculation', '{"learningGoal":"Einnahmen, Ausgaben und verfügbares Geld planen.","coreIdea":"Ein Budget zeigt, ob dein Geld reicht und was übrig bleibt.","everydayScenario":"Du bekommst Taschengeld und planst Snacks, Freizeit, Sparen und Restbetrag.","misconception":"Solange noch Geld auf dem Konto ist, ist alles in Ordnung.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Budget: Einnahmen und Ausgaben'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Budget: Einnahmen und Ausgaben'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Budget', 'Einnahmen', 'Ausgaben', 'Überschuss', 'Fehlbetrag', 'feste Ausgaben', 'variable Ausgaben']::text[], '{"competenceGoal":"Einnahmen, Ausgaben und verfügbares Geld planen.","typicalMisconception":"Solange noch Geld auf dem Konto ist, ist alles in Ordnung.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Solange noch Geld auf dem Konto ist, ist alles in Ordnung.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Budget: Einnahmen und Ausgaben“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Budget: Einnahmen und Ausgaben“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Budget: Einnahmen und Ausgaben“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
  ('konzept_geld_auf_konto', 7, 'tb_geld_wert_entscheidungen', '{"de":"Geld auf dem Konto"}'::jsonb, true, ARRAY['konzept_budget']::text[], 2, '{"learners_10_14":"Geld auf dem Konto: Geld auf dem Konto ist als Guthaben sichtbar und verändert sich durch Buchungen. Beispiel: Eine Überweisung erhöht den Kontostand; eine Kartenzahlung senkt ihn. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Auf meinem Konto liegt mein Geld als Scheine in einem eigenen Fach bei der Bank.“.","young_adults":"Geld auf dem Konto: Geld auf dem Konto ist als Guthaben sichtbar und verändert sich durch Buchungen. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Eine Überweisung erhöht den Kontostand; eine Kartenzahlung senkt ihn.","parents_teachers":"Lernziel: Kontostand, Guthaben und digitale Zahlungen verstehen. Didaktischer Fokus: Geld auf dem Konto ist als Guthaben sichtbar und verändert sich durch Buchungen. Typische Fehlvorstellung: „Auf meinem Konto liegt mein Geld als Scheine in einem eigenen Fach bei der Bank.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'calculation', '{"learningGoal":"Kontostand, Guthaben und digitale Zahlungen verstehen.","coreIdea":"Geld auf dem Konto ist als Guthaben sichtbar und verändert sich durch Buchungen.","everydayScenario":"Eine Überweisung erhöht den Kontostand; eine Kartenzahlung senkt ihn.","misconception":"Auf meinem Konto liegt mein Geld als Scheine in einem eigenen Fach bei der Bank.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Geld auf dem Konto'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Geld auf dem Konto'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Konto', 'Kontostand', 'Guthaben', 'Überweisung', 'Abbuchung', 'Kartenzahlung', 'PIN']::text[], '{"competenceGoal":"Kontostand, Guthaben und digitale Zahlungen verstehen.","typicalMisconception":"Auf meinem Konto liegt mein Geld als Scheine in einem eigenen Fach bei der Bank.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Auf meinem Konto liegt mein Geld als Scheine in einem eigenen Fach bei der Bank.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Geld auf dem Konto“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Geld auf dem Konto“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Geld auf dem Konto“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
  ('konzept_konten', 8, 'tb_geld_wert_entscheidungen', '{"de":"Girokonto, Tagesgeld, Sparbuch"}'::jsonb, false, ARRAY['konzept_geld_auf_konto']::text[], 2, '{"learners_10_14":"Girokonto, Tagesgeld, Sparbuch: Nicht jedes Konto ist für denselben Zweck da. Beispiel: Taschengeld läuft über ein Girokonto; Rücklagen liegen eher auf Tagesgeld. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Konto ist Konto – es gibt keinen wichtigen Unterschied.“.","young_adults":"Girokonto, Tagesgeld, Sparbuch: Nicht jedes Konto ist für denselben Zweck da. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Taschengeld läuft über ein Girokonto; Rücklagen liegen eher auf Tagesgeld.","parents_teachers":"Lernziel: Verschiedene Kontoarten nach Zweck, Verfügbarkeit und Nutzung unterscheiden. Didaktischer Fokus: Nicht jedes Konto ist für denselben Zweck da. Typische Fehlvorstellung: „Konto ist Konto – es gibt keinen wichtigen Unterschied.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'understanding', '{"learningGoal":"Verschiedene Kontoarten nach Zweck, Verfügbarkeit und Nutzung unterscheiden.","coreIdea":"Nicht jedes Konto ist für denselben Zweck da.","everydayScenario":"Taschengeld läuft über ein Girokonto; Rücklagen liegen eher auf Tagesgeld.","misconception":"Konto ist Konto – es gibt keinen wichtigen Unterschied.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Girokonto, Tagesgeld, Sparbuch'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Girokonto, Tagesgeld, Sparbuch'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Girokonto', 'Tagesgeldkonto', 'Sparbuch', 'Zinsen', 'Zahlungsverke