  ('konzept_nominal_real', 16, 'tb_sparen_zinsen_inflation', '{"de":"Nominal und real"}'::jsonb, true, ARRAY['konzept_kaufkraft']::text[], 5, '{"learners_10_14":"Nominal und real: Nominal ist die Zahl; real ist, was man dafür kaufen kann. Beispiel: Du bekommst 2 Prozent mehr Geld, aber die Preise steigen um 5 Prozent. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Mehr Euro bedeutet automatisch, dass ich reicher bin.“.","young_adults":"Nominal und real: Nominal ist die Zahl; real ist, was man dafür kaufen kann. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Du bekommst 2 Prozent mehr Geld, aber die Preise steigen um 5 Prozent.","parents_teachers":"Lernziel: Nominale Geldbeträge und reale Kaufkraft unterscheiden. Didaktischer Fokus: Nominal ist die Zahl; real ist, was man dafür kaufen kann. Typische Fehlvorstellung: „Mehr Euro bedeutet automatisch, dass ich reicher bin.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'calculation', '{"learningGoal":"Nominale Geldbeträge und reale Kaufkraft unterscheiden.","coreIdea":"Nominal ist die Zahl; real ist, was man dafür kaufen kann.","everydayScenario":"Du bekommst 2 Prozent mehr Geld, aber die Preise steigen um 5 Prozent.","misconception":"Mehr Euro bedeutet automatisch, dass ich reicher bin.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Nominal und real'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Nominal und real'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Nominal', 'real', 'Kaufkraft', 'Inflation', 'realer Wert', 'nominaler Wert']::text[], '{"competenceGoal":"Nominale Geldbeträge und reale Kaufkraft unterscheiden.","typicalMisconception":"Mehr Euro bedeutet automatisch, dass ich reicher bin.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Mehr Euro bedeutet automatisch, dass ich reicher bin.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Nominal und real“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Nominal und real“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Nominal und real“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
  ('konzept_sparen_reicht_nicht', 17, 'tb_sparen_zinsen_inflation', '{"de":"Warum Sparen allein nicht immer reicht"}'::jsonb, false, ARRAY['konzept_nominal_real', 'konzept_zinseszins']::text[], 5, '{"learners_10_14":"Warum Sparen allein nicht immer reicht: Sparen schafft Sicherheit; langfristig muss Geld seine Kaufkraft möglichst erhalten. Beispiel: Ein Ziel kostet heute 200 Euro und in einigen Jahren vielleicht 240 Euro. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Geld aufbewahren reicht immer, um später genauso viel kaufen zu können.“.","young_adults":"Warum Sparen allein nicht immer reicht: Sparen schafft Sicherheit; langfristig muss Geld seine Kaufkraft möglichst erhalten. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Ein Ziel kostet heute 200 Euro und in einigen Jahren vielleicht 240 Euro.","parents_teachers":"Lernziel: Verstehen, warum Sparen wichtig ist, langfristig aber Kaufkraft mitgedacht werden muss. Didaktischer Fokus: Sparen schafft Sicherheit; langfristig muss Geld seine Kaufkraft möglichst erhalten. Typische Fehlvorstellung: „Geld aufbewahren reicht immer, um später genauso viel kaufen zu können.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'decision', '{"learningGoal":"Verstehen, warum Sparen wichtig ist, langfristig aber Kaufkraft mitgedacht werden muss.","coreIdea":"Sparen schafft Sicherheit; langfristig muss Geld seine Kaufkraft möglichst erhalten.","everydayScenario":"Ein Ziel kostet heute 200 Euro und in einigen Jahren vielleicht 240 Euro.","misconception":"Geld aufbewahren reicht immer, um später genauso viel kaufen zu können.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Warum Sparen allein nicht immer reicht'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Warum Sparen allein nicht immer reicht'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Sparen', 'Kaufkraft', 'Inflation', 'langfristiges Ziel', 'kurzfristiges Ziel', 'Sicherheit', 'Rendite']::text[], '{"competenceGoal":"Verstehen, warum Sparen wichtig ist, langfristig aber Kaufkraft mitgedacht werden muss.","typicalMisconception":"Geld aufbewahren reicht immer, um später genauso viel kaufen zu können.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Geld aufbewahren reicht immer, um später genauso viel kaufen zu können.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Warum Sparen allein nicht immer reicht“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Warum Sparen allein nicht immer reicht“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Warum Sparen allein nicht immer reicht“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
  ('konzept_unternehmen', 18, 'tb_unternehmen_verstehen', '{"de":"Was ist ein Unternehmen?"}'::jsonb, false, ARRAY['konzept_geld', 'konzept_bezahlen_vergleichen']::text[], 6, '{"learners_10_14":"Was ist ein Unternehmen?: Ein Unternehmen bietet etwas an, das Kunden brauchen oder möchten, und erhält dafür Geld. Beispiel: Eine Bäckerei verkauft Brot und bezahlt aus den Einnahmen Zutaten, Miete und Löhne. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Ein Unternehmen ist einfach ein großes Gebäude mit vielen Mitarbeitenden.“.","young_adults":"Was ist ein Unternehmen?: Ein Unternehmen bietet etwas an, das Kunden brauchen oder möchten, und erhält dafür Geld. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Eine Bäckerei verkauft Brot und bezahlt aus den Einnahmen Zutaten, Miete und Löhne.","parents_teachers":"Lernziel: Unternehmen als Organisationen verstehen, die Produkte oder Dienstleistungen anbieten. Didaktischer Fokus: Ein Unternehmen bietet etwas an, das Kunden brauchen oder möchten, und erhält dafür Geld. Typische Fehlvorstellung: „Ein Unternehmen ist einfach ein großes Gebäude mit vielen Mitarbeitenden.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'understanding', '{"learningGoal":"Unternehmen als Organisationen verstehen, die Produkte oder Dienstleistungen anbieten.","coreIdea":"Ein Unternehmen bietet etwas an, das Kunden brauchen oder möchten, und erhält dafür Geld.","everydayScenario":"Eine Bäckerei verkauft Brot und bezahlt aus den Einnahmen Zutaten, Miete und Löhne.","misconception":"Ein Unternehmen ist einfach ein großes Gebäude mit vielen Mitarbeitenden.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Was ist ein Unternehmen?'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Was ist ein Unternehmen?'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Unternehmen', 'Firma', 'Produkt', 'Dienstleistung', 'Kunde', 'Einnahmen', 'Kosten', 'Gewinn']::text[], '{"competenceGoal":"Unternehmen als Organisationen verstehen, die Produkte oder Dienstleistungen anbieten.","typicalMisconception":"Ein Unternehmen ist einfach ein großes Gebäude mit vielen Mitarbeitenden.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Ein Unternehmen ist einfach ein großes Gebäude mit vielen Mitarbeitenden.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Was ist ein Unternehmen?“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Was ist ein Unternehmen?“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Was ist ein Unternehmen?“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
  ('konzept_problem_loesen', 19, 'tb_unternehmen_verstehen', '{"de":"Welches Problem löst ein Unternehmen?"}'::jsonb, false, ARRAY['konzept_unternehmen']::text[], 6, '{"learners_10_14":"Welches Problem löst ein Unternehmen?: Ein Unternehmen ist stärker, wenn Menschen sein Angebot wirklich brauchen oder gerne nutzen. Beispiel: Ein Fahrradladen hilft Menschen, mobil zu bleiben oder ein kaputtes Fahrrad zu reparieren. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Ein Unternehmen ist erfolgreich, wenn es einfach nur viel Werbung macht.“.","young_adults":"Welches Problem löst ein Unternehmen?: Ein Unternehmen ist stärker, wenn Menschen sein Angebot wirklich brauchen oder gerne nutzen. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Ein Fahrradladen hilft Menschen, mobil zu bleiben oder ein kaputtes Fahrrad zu reparieren.","parents_teachers":"Lernziel: Kundennutzen und Problem-Lösung als Kern von Unternehmen verstehen. Didaktischer Fokus: Ein Unternehmen ist stärker, wenn Menschen sein Angebot wirklich brauchen oder gerne nutzen. Typische Fehlvorstellung: „Ein Unternehmen ist erfolgreich, wenn es einfach nur viel Werbung macht.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'decision', '{"learningGoal":"Kundennutzen und Problem-Lösung als Kern von Unternehmen verstehen.","coreIdea":"Ein Unternehmen ist stärker, wenn Menschen sein Angebot wirklich brauchen oder gerne nutzen.","everydayScenario":"Ein Fahrradladen hilft Menschen, mobil zu bleiben oder ein kaputtes Fahrrad zu reparieren.","misconception":"Ein Unternehmen ist erfolgreich, wenn es einfach nur viel Werbung macht.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Welches Problem löst ein Unternehmen?'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Welches Problem löst ein Unternehmen?'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Problem', 'Lösung', 'Kundennutzen', 'Bedarf', 'Zielgruppe', 'Nutzenversprechen']::text[], '{"competenceGoal":"Kundennutzen und Problem-Lösung als Kern von Unternehmen verstehen.","typicalMisconception":"Ein Unternehmen ist erfolgreich, wenn es einfach nur viel Werbung macht.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Ein Unternehmen ist erfolgreich, wenn es einfach nur viel Werbung macht.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Welches Problem löst ein Unternehmen?“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Welches Problem löst ein Unternehmen?“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Welches Problem löst ein Unternehmen?“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
  ('konzept_produkt_dienstleistung_kunde', 20, 'tb_unternehmen_verstehen', '{"de":"Produkt, Dienstleistung und Kunde"}'::jsonb, false, ARRAY['konzept_problem_loesen']::text[], 6, '{"learners_10_14":"Produkt, Dienstleistung und Kunde: Unternehmen können Dinge verkaufen, Leistungen erbringen oder beides kombinieren. Beispiel: Ein Buchladen verkauft Bücher; ein Friseur erbringt eine Dienstleistung. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Nur Dinge, die man anfassen kann, sind echte Produkte von Unternehmen.“.","young_adults":"Produkt, Dienstleistung und Kunde: Unternehmen können Dinge verkaufen, Leistungen erbringen oder beides kombinieren. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Ein Buchladen verkauft Bücher; ein Friseur erbringt eine Dienstleistung.","parents_teachers":"Lernziel: Produkt, Dienstleistung, Nutzer, Kunde und Zahler unterscheiden. Didaktischer Fokus: Unternehmen können Dinge verkaufen, Leistungen erbringen oder beides kombinieren. Typische Fehlvorstellung: „Nur Dinge, die man anfassen kann, sind echte Produkte von Unternehmen.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'understanding', '{"learningGoal":"Produkt, Dienstleistung, Nutzer, Kunde und Zahler unterscheiden.","coreIdea":"Unternehmen können Dinge verkaufen, Leistungen erbringen oder beides kombinieren.","everydayScenario":"Ein Buchladen verkauft Bücher; ein Friseur erbringt eine Dienstleistung.","misconception":"Nur Dinge, die man anfassen kann, sind echte Produkte von Unternehmen.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Produkt, Dienstleistung und Kunde'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Feh