  ('konzept_geschaeftsmodell', 21, 'tb_unternehmen_verstehen', '{"de":"Geschäftsmodell – Wer zahlt wofür?"}'::jsonb, false, ARRAY['konzept_produkt_dienstleistung_kunde']::text[], 7, '{"learners_10_14":"Geschäftsmodell – Wer zahlt wofür?: Ein Geschäftsmodell zeigt, wie ein Unternehmen Nutzen schafft und Geld verdient. Beispiel: Ein Fitnessstudio verdient Geld durch monatliche Mitgliedsbeiträge. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Ein Geschäftsmodell bedeutet nur: Das Unternehmen verkauft irgendetwas.“.","young_adults":"Geschäftsmodell – Wer zahlt wofür?: Ein Geschäftsmodell zeigt, wie ein Unternehmen Nutzen schafft und Geld verdient. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Ein Fitnessstudio verdient Geld durch monatliche Mitgliedsbeiträge.","parents_teachers":"Lernziel: Geschäftsmodelle als Logik von Nutzen, Kunden, Preis und Kosten verstehen. Didaktischer Fokus: Ein Geschäftsmodell zeigt, wie ein Unternehmen Nutzen schafft und Geld verdient. Typische Fehlvorstellung: „Ein Geschäftsmodell bedeutet nur: Das Unternehmen verkauft irgendetwas.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'decision', '{"learningGoal":"Geschäftsmodelle als Logik von Nutzen, Kunden, Preis und Kosten verstehen.","coreIdea":"Ein Geschäftsmodell zeigt, wie ein Unternehmen Nutzen schafft und Geld verdient.","everydayScenario":"Ein Fitnessstudio verdient Geld durch monatliche Mitgliedsbeiträge.","misconception":"Ein Geschäftsmodell bedeutet nur: Das Unternehmen verkauft irgendetwas.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Geschäftsmodell – Wer zahlt wofür?'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Geschäftsmodell – Wer zahlt wofür?'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Geschäftsmodell', 'Zielgruppe', 'Nutzenversprechen', 'Abo', 'Werbung', 'Provision', 'Freemium', 'Kostenstruktur']::text[], '{"competenceGoal":"Geschäftsmodelle als Logik von Nutzen, Kunden, Preis und Kosten verstehen.","typicalMisconception":"Ein Geschäftsmodell bedeutet nur: Das Unternehmen verkauft irgendetwas.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Ein Geschäftsmodell bedeutet nur: Das Unternehmen verkauft irgendetwas.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Geschäftsmodell – Wer zahlt wofür?“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Geschäftsmodell – Wer zahlt wofür?“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Geschäftsmodell – Wer zahlt wofür?“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
  ('konzept_umsatz', 22, 'tb_unternehmen_verstehen', '{"de":"Was ist Umsatz?"}'::jsonb, true, ARRAY['konzept_geschaeftsmodell']::text[], 7, '{"learners_10_14":"Was ist Umsatz?: Umsatz ist nicht Gewinn; Umsatz zeigt nur, wie viel durch Verkäufe hereinkommt. Beispiel: Ein Kiosk verkauft 20 Getränke für je 3 Euro und macht 60 Euro Umsatz. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Hoher Umsatz bedeutet automatisch hoher Gewinn.“.","young_adults":"Was ist Umsatz?: Umsatz ist nicht Gewinn; Umsatz zeigt nur, wie viel durch Verkäufe hereinkommt. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Ein Kiosk verkauft 20 Getränke für je 3 Euro und macht 60 Euro Umsatz.","parents_teachers":"Lernziel: Umsatz als eingenommenes Geld aus Verkäufen vor Kosten verstehen. Didaktischer Fokus: Umsatz ist nicht Gewinn; Umsatz zeigt nur, wie viel durch Verkäufe hereinkommt. Typische Fehlvorstellung: „Hoher Umsatz bedeutet automatisch hoher Gewinn.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'calculation', '{"learningGoal":"Umsatz als eingenommenes Geld aus Verkäufen vor Kosten verstehen.","coreIdea":"Umsatz ist nicht Gewinn; Umsatz zeigt nur, wie viel durch Verkäufe hereinkommt.","everydayScenario":"Ein Kiosk verkauft 20 Getränke für je 3 Euro und macht 60 Euro Umsatz.","misconception":"Hoher Umsatz bedeutet automatisch hoher Gewinn.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Was ist Umsatz?'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Was ist Umsatz?'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Umsatz', 'Verkauf', 'Preis', 'Menge', 'Erlös', 'Einnahmen', 'Kosten', 'Gewinn']::text[], '{"competenceGoal":"Umsatz als eingenommenes Geld aus Verkäufen vor Kosten verstehen.","typicalMisconception":"Hoher Umsatz bedeutet automatisch hoher Gewinn.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Hoher Umsatz bedeutet automatisch hoher Gewinn.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Was ist Umsatz?“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Was ist Umsatz?“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Was ist Umsatz?“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
