  ('konzept_aktie', 30, 'tb_aktien_eigentum', '{"de":"Was ist eine Aktie?"}'::jsonb, false, ARRAY['konzept_unternehmen', 'konzept_gewinn']::text[], 11, '{"learners_10_14":"Was ist eine Aktie?: Wer eine Aktie besitzt, besitzt einen kleinen Anteil an einem Unternehmen. Beispiel: Ein Unternehmen wird in viele kleine Anteile aufgeteilt; eine Aktie ist ein solcher Anteil. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Eine Aktie ist nur ein Preis, der hoch oder runter geht.“.","young_adults":"Was ist eine Aktie?: Wer eine Aktie besitzt, besitzt einen kleinen Anteil an einem Unternehmen. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Ein Unternehmen wird in viele kleine Anteile aufgeteilt; eine Aktie ist ein solcher Anteil.","parents_teachers":"Lernziel: Aktien als kleine Anteile an einem Unternehmen verstehen. Didaktischer Fokus: Wer eine Aktie besitzt, besitzt einen kleinen Anteil an einem Unternehmen. Typische Fehlvorstellung: „Eine Aktie ist nur ein Preis, der hoch oder runter geht.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'understanding', '{"learningGoal":"Aktien als kleine Anteile an einem Unternehmen verstehen.","coreIdea":"Wer eine Aktie besitzt, besitzt einen kleinen Anteil an einem Unternehmen.","everydayScenario":"Ein Unternehmen wird in viele kleine Anteile aufgeteilt; eine Aktie ist ein solcher Anteil.","misconception":"Eine Aktie ist nur ein Preis, der hoch oder runter geht.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Was ist eine Aktie?'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Was ist eine Aktie?'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Aktie', 'Anteil', 'Unternehmen', 'Aktiengesellschaft', 'Aktionär', 'Eigentum', 'Kurs', 'Risiko']::text[], '{"competenceGoal":"Aktien als kleine Anteile an einem Unternehmen verstehen.","typicalMisconception":"Eine Aktie ist nur ein Preis, der hoch oder runter geht.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Eine Aktie ist nur ein Preis, der hoch oder runter geht.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Was ist eine Aktie?“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Was ist eine Aktie?“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Was ist eine Aktie?“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
  ('konzept_eigentum_am_unternehmen', 31, 'tb_aktien_eigentum', '{"de":"Eigentum am Unternehmen"}'::jsonb, true, ARRAY['konzept_aktie']::text[], 11, '{"learners_10_14":"Eigentum am Unternehmen: Eigentum an einem Unternehmen bedeutet Beteiligung, aber nicht automatische Kontrolle. Beispiel: Wer wenige von sehr vielen Aktien besitzt, ist beteiligt, entscheidet aber nicht allein. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Wenn ich eine Aktie besitze, darf ich im Unternehmen alles bestimmen.“.","young_adults":"Eigentum am Unternehmen: Eigentum an einem Unternehmen bedeutet Beteiligung, aber nicht automatische Kontrolle. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Wer wenige von sehr vielen Aktien besitzt, ist beteiligt, entscheidet aber nicht allein.","parents_teachers":"Lernziel: Aktionärseigentum, Rechte und Einfluss nach Anteil verstehen. Didaktischer Fokus: Eigentum an einem Unternehmen bedeutet Beteiligung, aber nicht automatische Kontrolle. Typische Fehlvorstellung: „Wenn ich eine Aktie besitze, darf ich im Unternehmen alles bestimmen.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'calculation', '{"learningGoal":"Aktionärseigentum, Rechte und Einfluss nach Anteil verstehen.","coreIdea":"Eigentum an einem Unternehmen bedeutet Beteiligung, aber nicht automatische Kontrolle.","everydayScenario":"Wer wenige von sehr vielen Aktien besitzt, ist beteiligt, entscheidet aber nicht allein.","misconception":"Wenn ich eine Aktie besitze, darf ich im Unternehmen alles bestimmen.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Eigentum am Unternehmen'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Eigentum am Unternehmen'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Aktionär', 'Eigentumsanteil', 'Stimmrecht', 'Hauptversammlung', 'Anteil', 'Stammaktie', 'Vorzugsaktie']::text[], '{"competenceGoal":"Aktionärseigentum, Rechte und Einfluss nach Anteil verstehen.","typicalMisconception":"Wenn ich eine Aktie besitze, darf ich im Unternehmen alles bestimmen.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Wenn ich eine Aktie besitze, darf ich im Unternehmen alles bestimmen.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Eigentum am Unternehmen“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Eigentum am Unternehmen“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Eigentum am Unternehmen“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
  ('konzept_warum_aktien_ausgeben', 32, 'tb_aktien_eigentum', '{"de":"Warum geben Unternehmen Aktien aus?"}'::jsonb, false, ARRAY['konzept_aktie', 'konzept_geschaeftsmodell', 'konzept_vermoegen_schulden_eigenkapital']::text[], 12, '{"learners_10_14":"Warum geben Unternehmen Aktien aus?: Aktien können Unternehmen helfen, Kapital zu bekommen; dafür geben sie Eigentumsanteile ab. Beispiel: Ein Unternehmen braucht Geld für Maschinen oder Wachstum und verkauft neue Anteile. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Wenn ich eine Aktie an der Börse kaufe, bekommt das Unternehmen immer direkt mein Geld.“.","young_adults":"Warum geben Unternehmen Aktien aus?: Aktien können Unternehmen helfen, Kapital zu bekommen; dafür geben sie Eigentumsanteile ab. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Ein Unternehmen braucht Geld für Maschinen oder Wachstum und verkauft neue Anteile.","parents_teachers":"Lernziel: Aktienausgabe als Möglichkeit zur Kapitalbeschaffung verstehen. Didaktischer Fokus: Aktien können Unternehmen helfen, Kapital zu bekommen; dafür geben sie Eigentumsanteile ab. Typische Fehlvorstellung: „Wenn ich eine Aktie an der Börse kaufe, bekommt das Unternehmen immer direkt mein Geld.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'understanding', '{"learningGoal":"Aktienausgabe als Möglichkeit zur Kapitalbeschaffung verstehen.","coreIdea":"Aktien können Unternehmen helfen, Kapital zu bekommen; dafür geben sie Eigentumsanteile ab.","everydayScenario":"Ein Unternehmen braucht Geld für Maschinen oder Wachstum und verkauft neue Anteile.","misconception":"Wenn ich eine Aktie an der Börse kaufe, bekommt das Unternehmen immer direkt mein Geld.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Warum geben Unternehmen Aktien aus?'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Warum geben Unternehmen Aktien aus?'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Aktienausgabe', 'Kapital', 'Eigenkapital', 'Börsengang', 'Kapitalerhöhung', 'Anleger', 'Verwässerung']::text[], '{"competenceGoal":"Aktienausgabe als Möglichkeit zur Kapitalbeschaffung verstehen.","typicalMisconception":"Wenn ich eine Aktie an der Börse kaufe, bekommt das Unternehmen immer direkt mein Geld.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Wenn ich eine Aktie an der Börse kaufe, bekommt das Unternehmen immer direkt mein Geld.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Warum geben Unternehmen Aktien aus?“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Warum geben Unternehmen Aktien aus?“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Warum geben Unternehmen Aktien aus?“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
  ('konzept_aktionaer_sein', 33, 'tb_aktien_eigentum', '{"de":"Was bedeutet Aktionär sein?"}'::jsonb, false, ARRAY['konzept_eigentum_am_unternehmen']::text[], 12, '{"learners_10_14":"Was bedeutet Aktionär sein?: Aktionäre sind Miteigentümer, nicht bloß Kunden oder Fans. Beispiel: Du kaufst Schuhe als Kunde; Aktie besitzen macht dich zum Miteigentümer. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Wenn ich Produkte einer Firma kaufe, bin ich automatisch Aktionär.“.","young_adults":"Was bedeutet Aktionär sein?: Aktionäre sind Miteigentümer, nicht bloß Kunden oder Fans. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Du kaufst Schuhe als Kunde; Aktie besitzen macht dich zum Miteigentümer.","parents_teachers":"Lernziel: Aktionärsrolle von Kundenrolle unterscheiden. Didaktischer Fokus: Aktionäre sind Miteigentümer, nicht bloß Kunden oder Fans. Typische Fehlvorstellung: „Wenn ich Produkte einer Firma kaufe, bin ich automatisch Aktionär.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'understanding', '{"learningGoal":"Aktionärsrolle von Kundenrolle unterscheiden.","coreIdea":"Aktionäre sind Miteigentümer, nicht bloß Kunden oder Fans.","everydayScenario":"Du kaufst Schuhe als Kunde; Aktie besitzen macht dich zum Miteigentümer.","misconception":"Wenn ich Produkte einer Firma kaufe, bin ich automatisch Aktionär.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Was bedeutet Aktionär sein?'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Was bedeutet Aktionär sein?'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Aktionär', 'Kunde', 'Eigentümer', 'Beteiligung', 'Stimmrecht', 'Dividende', 'Kursrisiko']::text[], '{"competenceGoal":"Aktionärsrolle von Kundenrolle unterscheiden.","typicalMisconception":"Wenn ich Produkte einer Firma kaufe, bin ich automatisch Aktionär.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Wenn ich Produkte einer Firma kaufe, bin ich automatisch Aktionär.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Was bedeutet Aktionär sein?“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Was bedeutet Aktionär sein?“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Was bedeutet Aktionär sein?“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
  ('konzept_chancen_risiken_aktie', 34, 'tb_aktien_eigentum', '{"de":"Chancen und Risiken einer Aktie"}'::jsonb, false, ARRAY['konzept_aktionaer_sein', 'konzept_unternehmen_scheitern']::text[], 13, '{"learners_10_14":"Chancen und Risiken einer Aktie: Aktien bieten Chancen, können aber stark schwanken und Verluste verursachen. Beispiel: Ein erfolgreiches Unternehmen kann steigende Kurse haben; ein schwaches Unternehmen fallende. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Eine bekannte Aktie ist automatisch sicher.“.","young_adults":"Chancen und Risiken einer Aktie: Aktien bieten Chancen, können aber stark schwanken und Verluste verursachen. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Ein erfolgreiches Unternehmen kann steigende Kurse haben; ein schwaches Unternehmen fallende.","parents_teachers":"Lernziel: Chancen auf Wertsteigerung und Dividenden sowie Verlustrisiken verstehen. Didaktischer Fokus: Aktien bieten Chancen, können aber stark schwanken und Verluste verursachen. Typische Fehlvorstellung: „Eine bekannte Aktie ist automatisch sicher.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'reflection', '{"learningGoal":"Chancen auf Wertsteigerung und Dividenden sowie Verlustrisiken verstehen.","coreIdea":"Aktien bieten Chancen, können aber stark schwanken und Verluste verursachen.","everydayScenario":"Ein erfolgreiches Unternehmen kann steigende Kurse haben; ein schwaches Unternehmen fallende.","misconception":"Eine bekannte Aktie ist automatisch sicher.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Chancen und Risiken einer Aktie'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellu