  ('konzept_depot', 75, 'tb_depot_kosten_umsetzung', '{"de":"Was ist ein Depot?"}'::jsonb, false, ARRAY['konzept_etf', 'konzept_aktie']::text[], 33, '{"learners_10_14":"Was ist ein Depot?: Im Depot liegen Wertpapiere; auf dem Verrechnungskonto liegt Geld. Beispiel: Nach dem Kauf siehst du einen ETF als Position im Depot. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Im Depot liegt einfach mein Bargeld.“.","young_adults":"Was ist ein Depot?: Im Depot liegen Wertpapiere; auf dem Verrechnungskonto liegt Geld. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Nach dem Kauf siehst du einen ETF als Position im Depot.","parents_teachers":"Lernziel: Depot als Aufbewahrungs- und Verwaltungsort für Wertpapiere verstehen. Didaktischer Fokus: Im Depot liegen Wertpapiere; auf dem Verrechnungskonto liegt Geld. Typische Fehlvorstellung: „Im Depot liegt einfach mein Bargeld.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'understanding', '{"learningGoal":"Depot als Aufbewahrungs- und Verwaltungsort für Wertpapiere verstehen.","coreIdea":"Im Depot liegen Wertpapiere; auf dem Verrechnungskonto liegt Geld.","everydayScenario":"Nach dem Kauf siehst du einen ETF als Position im Depot.","misconception":"Im Depot liegt einfach mein Bargeld.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Was ist ein Depot?'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Was ist ein Depot?'' könnte dich zu einer schlechten Entscheidung verleiten?"}'::jsonb, ARRAY['Depot', 'Wertpapier', 'Position', 'Aktie', 'ETF', 'Kurswert', 'Verrechnungskonto', 'Transaktion']::text[], '{"competenceGoal":"Depot als Aufbewahrungs- und Verwaltungsort für Wertpapiere verstehen.","typicalMisconception":"Im Depot liegt einfach mein Bargeld.","discussionPrompt":"Was würde passieren, wenn man die Fehlvorstellung „Im Depot liegt einfach mein Bargeld.“ glaubt?","classroomActivity":"Die Lernenden erstellen ein eigenes Beispiel zu „Was ist ein Depot?“ und markieren Begriff, Risiko, Kosten und Entscheidung."}'::jsonb, '{"conversationPrompt":"Wo begegnet uns „Was ist ein Depot?“ im Alltag?","everydayExercise":"Gemeinsam ein kleines Beispiel zu „Was ist ein Depot?“ suchen und prüfen: Was ist sicher, was ist unklar, was kostet es?"}'::jsonb),
  ('konzept_verrechnungskonto', 76, 'tb_depot_kosten_umsetzung', '{"de":"Was ist ein Verrechnungskonto?"}'::jsonb, true, ARRAY['konzept_depot', 'konzept_geld_auf_konto']::text[], 33, '{"learners_10_14":"Was ist ein Verrechnungskonto?: Das Verrechnungskonto wickelt Käufe, Verkäufe, Gebühren und Ausschüttungen ab. Beispiel: Beim ETF-Kauf wird Geld vom Verrechnungskonto abgebucht. Wichtig ist die Abgrenzung zur Fehlvorstellung: „Wenn ich einen ETF verkaufe, bekomme ich sofort Bargeld in die Hand.“.","young_adults":"Was ist ein Verrechnungskonto?: Das Verrechnungskonto wickelt Käufe, Verkäufe, Gebühren und Ausschüttungen ab. Für echte Finanzentscheidungen bedeutet das: Begriffe, Kosten, Risiken, Zeitraum, Alternativen und die eigene Situation müssen zusammen betrachtet werden. Das Beispiel zeigt den praktischen Kern: Beim ETF-Kauf wird Geld vom Verrechnungskonto abgebucht.","parents_teachers":"Lernziel: Verrechnungskonto als Geldseite des Depots verstehen. Didaktischer Fokus: Das Verrechnungskonto wickelt Käufe, Verkäufe, Gebühren und Ausschüttungen ab. Typische Fehlvorstellung: „Wenn ich einen ETF verkaufe, bekomme ich sofort Bargeld in die Hand.“. Unterrichtsimpuls: Die Lernenden übertragen das Beispiel auf eine eigene Alltagssituation und benennen Grenzen der Aussage."}'::jsonb, ARRAY['erklaeren', 'erkennen', 'verstehen', 'anwenden', 'meistern']::text[], 'calculation', '{"learningGoal":"Verrechnungskonto als Geldseite des Depots verstehen.","coreIdea":"Das Verrechnungskonto wickelt Käufe, Verkäufe, Gebühren und Ausschüttungen ab.","everydayScenario":"Beim ETF-Kauf wird Geld vom Verrechnungskonto abgebucht.","misconception":"Wenn ich einen ETF verkaufe, bekomme ich sofort Bargeld in die Hand.","transferTask":"Beschreibe ein eigenes Beispiel zu ''Was ist ein Verrechnungskonto?'' und erkläre, welche Entscheidung oder welches Risiko darin steckt.","reflectionPrompt":"Welche Fehlvorstellung zu ''Was ist ein Verrechnungskonto?'' könnte dich zu einer schlechten Entscheidung